import "@maersk-global/mds-components-core/mc-card";

// HTML
<mc-card
  heading="Supply Chain and Logistics"
  subheading="Integrated logistics"
  footer="12 September 2022"
  image="/packages/mc-card/stories/images/supply-chain-logistics_illustration.svg"
  clickable
  @click="\${(event) => {
    console.log('Card clicked', event);
  }}"
>
  We focus on solving your supply chain needs from end to end, taking the complexity out of container shipping for you.
</mc-card>

advanced.SubheadingAsASlot:
// JavaScript
import "@maersk-global/mds-components-core/mc-card";
import "@maersk-global/mds-components-core/mc-tag";

// CSS
mc-card {
  width: 400px;
}

.subheading {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

// HTML
<mc-card heading="Costs" footer="Completed on 2025-8-22">
  <div slot="subheading" class="subheading">
    Priority Mail Express <mc-tag appearance="success">Completed</mc-tag>
  </div>
  <mc-button
    label="Visit page"
    icon="square-arrow-up-right"
    appearance="neutral"
    variant="outlined"
    slot="actions"
  ></mc-button>
</mc-card>

